uint64_t UNIQUE_VAR(r)[3] = {0xffffffffffffffff, 0xffffffffffffffff, 0xffffffffffffffff};

static void __attribute__((noinline)) UNIQUE_FUNC(remove_tmp_dir)(const char* dir)
{
	DIR* dp = opendir(dir);
	if (dp == NULL) {
		if (errno == EACCES) {
			if (rmdir(dir))
	assert(0);
			return;
		}
	assert(0);
	}
	struct dirent* ep = 0;
	while ((ep = readdir(dp))) {
		if (strcmp(ep->d_name, ".") == 0 || strcmp(ep->d_name, "..") == 0)
			continue;
		char filename[FILENAME_MAX];
		snprintf(filename, sizeof(filename), "%s/%s", dir, ep->d_name);
		struct stat st;
		if (lstat(filename, &st))
	assert(0);
		if (S_ISDIR(st.st_mode)) {
			UNIQUE_FUNC(remove_tmp_dir)(filename);
			continue;
		}
		if (unlink(filename)) {
	assert(0);
		}
	}
	closedir(dp);
	while (rmdir(dir)) {
	assert(0);
	}
}

